    produto: product.name || null,

    codigo_do_preco: offer.code || $json?.body?.data?.offer?.code || null,
    nome_deste_preco: s($json?.body?.data?.purchase?.offer?.description, null),

    taxa_de_conversao_moeda_de_compra: n(comm?.[1]?.currency_conversion?.conversion_rate, 1.0),
    moeda_de_compra: purchase?.price?.currency_value || null,

    valor_de_compra_com_impostos: n(purchase?.full_price?.value, 0),
