    valor_de_compra_sem_impostos: n(
      purchase?.price?.value ?? $json?.body?.data?.actual_recurrence_value,
      0
    ),

    taxa_de_conversao_moeda_da_comissao: n($json?.body?.data?.commissions?.[1]?.currency_conversion_rate, 1.0),
    moeda_da_comissao: comm?.[1]?.currency_value || null,

    comissao_bruta_sem_impostos: n(comm?.[1]?.value, 0),
    minha_comissao: n(comm?.[1]?.value, 0),

    venda_feita_como: comm?.[1]?.source || null,
    comissao_do_produtor: n(comm?.[1]?.value, 0),

    comissao_do_afiliado: n($json?.body?.data?.commissions?.[2]?.value, 0),
    comissao_do_coprodutor: n($json?.body?.data?.commissions?.[3]?.value, 0),

