    outras_taxas: 0.00,

    nome_do_afiliado: affiliates?.[0]?.name || '',
    canal_usado_para_venda: purchase?.invoice_by || '',

    codigo_src: origin?.src || '',
    codigo_sck: $json.sck_normalized || origin?.sck || $json?.body?.data?.purchase?.sckPaymentLink || '',

