    quantidade_total_de_parcelas: n(pay?.installments_number, 0),
    quantidade_de_cobrancas: n($json?.body?.data?.purchase?.recurrence_number, 0),

    data_de_vencimento_vouchers: '2000-01-01 00:00:00',

