    estado_provincia: buyerAddr?.state || null,
    endereco: buyerAddr?.address || null,
    bairro: buyerAddr?.neighborhood || null,
    numero: buyerAddr?.number || null,
    complemento: buyerAddr?.complement || null,
    instagram: buyerAddr?.instagram || null,

