(function () {
  var root = $('Webhook').first().json || {};
  var s = String(
    root.body &&
    root.body.data &&
    root.body.data.purchase &&
    root.body.data.purchase.origin &&
    root.body.data.purchase.origin.sck
      ? root.body.data.purchase.origin.sck
      : ""
  );

  s = s
    .replace(/\s*[—–-]\s*C[oó]pia/gi, "")
    .replace(/\s+/g, " ")
    .trim();

  if (!s) return "";

  if (s.indexOf("||") !== -1) {
    return s
      .split("||")
      .map(function (v) {
        return String(v || "").trim();
      })
      .join("||");
  }

  var sources = [
    "ytv",
    "ttk",
    "msg",
    "ig",
    "fb",
    "an",
    "g",
    "s"
  ];

  var mediums = [
    "Instagram_Explore_Grid_Home",
    "Facebook_Mobile_Feed",
    "Facebook_Mobile_Reels",
    "Instagram_Stories",
    "Instagram_Explore",
    "Instagram_Reels",
    "Instagram_Feed",
    "Facebook_Stories"
  ];

  sources.sort(function (a, b) {
    return b.length - a.length;
  });

  mediums.sort(function (a, b) {
    return b.length - a.length;
  });

  var utm_source = "";
  var utm_medium = "";
  var utm_campaign = "";
  var utm_term = "";
  var utm_content = "";

  for (var i = 0; i < sources.length; i++) {
    var src = sources[i];

    if (s.toLowerCase().indexOf(src.toLowerCase()) === 0) {
      utm_source = src;
      s = s.slice(src.length).trim();
      break;
    }
  }

  if (!utm_source) return s;

  for (var j = 0; j < mediums.length; j++) {
    var med = mediums[j];

    if (s.indexOf(med) === 0) {
      utm_medium = med;
      s = s.slice(med.length).trim();
      break;
    }
  }

  if (!utm_medium) {
    var mediumMatch = s.match(/^([A-Za-z0-9_{}.-]+)(?=\[)/);

    if (mediumMatch) {
      utm_medium = String(mediumMatch[1] || "").trim();
      s = s.slice(utm_medium.length).trim();
    }
  }

  if (!utm_medium) {
    return [utm_source, s]
      .filter(Boolean)
      .map(function (v) {
        return String(v || "").trim();
      })
      .join("||");
  }

  var termStartMatch = s.match(/(\d{2}\[[^\]]+\])/);

  if (termStartMatch && typeof termStartMatch.index === "number") {
    var idxTerm = termStartMatch.index;

    utm_campaign = s.slice(0, idxTerm).trim();
    s = s.slice(idxTerm).trim();
  } else {
    var datePlusDigits = s.match(/(\d{4}\.\d{2}\.\d{2})(\d{2}\[)/);

    if (datePlusDigits && typeof datePlusDigits.index === "number") {
      var idxDate = datePlusDigits.index;

      utm_campaign = (s.slice(0, idxDate) + datePlusDigits[1]).trim();
      s = s.slice(idxDate + datePlusDigits[1].length).trim();
    } else {
      return [utm_source, utm_medium, s]
        .filter(Boolean)
        .map(function (v) {
          return String(v || "").trim();
        })
        .join("||");
    }
  }

  var contentMatch = s.match(/\[AD\d+\]/i);

  if (contentMatch && typeof contentMatch.index === "number") {
    var idxContent = contentMatch.index;

    utm_term = s.slice(0, idxContent).trim();
    utm_content = s.slice(idxContent).trim();
  } else {
    utm_term = s.trim();
  }

  return [
    utm_source,
    utm_medium,
    utm_campaign,
    utm_term,
    utm_content
  ]
    .map(function (v) {
      return String(v || "").trim();
    })
    .join("||");
})()
}}

